import jwt
import json
from datetime import datetime
from typing import Dict, Any, Optional, Tuple

def decode_jwt(token: str, secret: Optional[str] = None, verify: bool = False, 
               algorithms: Optional[list] = None) -> Tuple[Dict[str, Any], Dict[str, Any]]:
    """
    Decode and optionally verify a JWT token for debugging purposes.
    
    Args:
        token: JWT token string
        secret: Secret key for verification (optional)
        verify: Whether to verify signature (default: False for debugging)
        algorithms: List of allowed algorithms (default: ['HS256', 'HS512', 'RS256'])
    
    Returns:
        Tuple of (decoded_payload, header)
    """
    if algorithms is None:
        algorithms = ['HS256', 'HS512', 'RS256', 'RS512', 'ES256', 'ES512']
    
    # Decode header without verification
    header = jwt.get_unverified_header(token)
    
    if verify and secret:
        # Verify and decode
        payload = jwt.decode(token, secret, algorithms=algorithms)
    else:
        # Decode without verification for debugging
        payload = jwt.decode(token, options={"verify_signature": False}, algorithms=algorithms)
    
    return payload, header


def inspect_jwt(token: str, secret: Optional[str] = None, verify: bool = False) -> str:
    """
    Inspect JWT token and return formatted information.
    
    Args:
        token: JWT token string
        secret: Secret key for verification (optional)
        verify: Whether to verify signature
    
    Returns:
        Formatted string with token information
    """
    try:
        payload, header = decode_jwt(token, secret, verify)
        
        output = []
        output.append("=" * 60)
        output.append("JWT TOKEN INSPECTION")
        output.append("=" * 60)
        
        # Header
        output.append("\nHEADER:")
        output.append(json.dumps(header, indent=2))
        
        # Payload
        output.append("\nPAYLOAD:")
        output.append(json.dumps(payload, indent=2, default=str))
        
        # Expiration info
        if 'exp' in payload:
            exp_timestamp = payload['exp']
            exp_datetime = datetime.fromtimestamp(exp_timestamp)
            now = datetime.now()
            
            output.append("\nEXPIRATION INFO:")
            output.append(f"  Expires at: {exp_datetime}")
            output.append(f"  Current time: {now}")
            
            if exp_datetime > now:
                time_left = exp_datetime - now
                output.append(f"  Status: VALID (expires in {time_left})")
            else:
                time_expired = now - exp_datetime
                output.append(f"  Status: EXPIRED (expired {time_expired} ago)")
        
        # Issued at info
        if 'iat' in payload:
            iat_timestamp = payload['iat']
            iat_datetime = datetime.fromtimestamp(iat_timestamp)
            output.append(f"\nISSUED AT: {iat_datetime}")
        
        # Not before info
        if 'nbf' in payload:
            nbf_timestamp = payload['nbf']
            nbf_datetime = datetime.fromtimestamp(nbf_timestamp)
            output.append(f"NOT BEFORE: {nbf_datetime}")
        
        # Verification status
        output.append("\nVERIFICATION:")
        if verify and secret:
            output.append("  Signature: VERIFIED ✓")
        else:
            output.append("  Signature: NOT VERIFIED (debugging mode)")
        
        output.append("=" * 60)
        
        return "\n".join(output)
        
    except jwt.ExpiredSignatureError:
        return "ERROR: Token has expired"
    except jwt.InvalidTokenError as e:
        return f"ERROR: Invalid token - {str(e)}"
    except Exception as e:
        return f"ERROR: {str(e)}"


def verify_jwt(token: str, secret: str, algorithms: Optional[list] = None, 
               audience: Optional[str] = None, issuer: Optional[str] = None) -> Dict[str, Any]:
    """
    Verify JWT token with full validation.
    
    Args:
        token: JWT token string
        secret: Secret key for verification
        algorithms: List of allowed algorithms
        audience: Expected audience claim
        issuer: Expected issuer claim
    
    Returns:
        Decoded payload if valid
    
    Raises:
        jwt.InvalidTokenError: If token is invalid
    """
    if algorithms is None:
        algorithms = ['HS256', 'HS512', 'RS256']
    
    options = {}
    kwargs = {'algorithms': algorithms}
    
    if audience:
        kwargs['audience'] = audience
    if issuer:
        kwargs['issuer'] = issuer
    
    payload = jwt.decode(token, secret, **kwargs)
    return payload


# Quick usage functions
def quick_decode(token: str) -> Dict[str, Any]:
    """Quick decode without verification"""
    payload, _ = decode_jwt(token, verify=False)
    return payload


def quick_inspect(token: str) -> None:
    """Quick inspect and print to console"""
    print(inspect_jwt(token))


def get_token_claims(token: str) -> Dict[str, Any]:
    """Get all claims from token without verification"""
    return quick_decode(token)


def is_token_expired(token: str) -> bool:
    """Check if token is expired"""
    try:
        payload = quick_decode(token)
        if 'exp' in payload:
            exp_datetime = datetime.fromtimestamp(payload['exp'])
            return exp_datetime < datetime.now()
        return False
    except:
        return True